ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?award a :Awards .
    ?film a :Films .
    ?award p:hasFilm ?film .
    ?director a :Directors .
    ?film p:hasDirector ?director .
    ?director p:name ?name .
    ?award p:year ?year_f .
    FILTER((STR(?year_f) = "1983" || STR(?year_f) = "1983.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?award a :Awards .
    ?film a :Films .
    ?award p:hasFilm ?film .
    ?cinematographer a :Cinematographers .
    ?film p:hasCinematographer ?cinematographer .
    ?cinematographer p:name ?name .
    ?award p:year ?year_f .
    FILTER((STR(?year_f) = "1983" || STR(?year_f) = "1983.0"))
    BIND(?name AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?award a :Awards .
    ?film a :Films .
    ?award p:hasFilm ?film .
    ?director a :Directors .
    ?film p:hasDirector ?director .
    ?director p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?award a :Awards .
    ?film a :Films .
    ?award p:hasFilm ?film .
    ?cinematographer a :Cinematographers .
    ?film p:hasCinematographer ?cinematographer .
    ?cinematographer p:name ?name .
    ?award p:year ?year_f .
    FILTER((STR(?year_f) = "1983" || STR(?year_f) = "1983.0"))
    BIND(?name AS ?o0)
  }
} }
}
